const row = $json;

const studentName     = (row['Your Full Name'] || '').trim();
const email           = (row['Your Email Address'] || '').trim();
const targetRole      = (row['Target Job Role'] || '').trim();
const currentSkills   = (row['Your Current Skills'] || '').trim();
const experienceLevel = (row['Experience Level'] || 'Fresher').trim();
const location        = (row['Preferred Job Location'] || 'India').trim();
const weeklyHours     = parseFloat(row['How many hours per week can you learn new skills?']) || 5;

if (!studentName || !email || !targetRole || !currentSkills) {
  throw new Error('Name, Email, Target Role, and Current Skills are required.');
}

const skillsArray = currentSkills
  .split(',')
  .map(s => s.trim())
  .filter(s => s.length > 0);

const encodedRole     = encodeURIComponent(targetRole);
const encodedLocation = encodeURIComponent(location);
const linkedinUrl = `https://www.linkedin.com/jobs/search/?keywords=${encodedRole}&location=${encodedLocation}&sortBy=R`;

const today = new Date();
const day30 = new Date(today); day30.setDate(today.getDate() + 30);
const day60 = new Date(today); day60.setDate(today.getDate() + 60);
const day90 = new Date(today); day90.setDate(today.getDate() + 90);

const fmt = d => d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

return [{
  json: {
    studentName,
    email,
    targetRole,
    currentSkills,
    skillsArray,
    skillsCount: skillsArray.length,
    experienceLevel,
    location,
    weeklyHours,
    linkedinUrl,
    today: fmt(today),
    day30: fmt(day30),
    day60: fmt(day60),
    day90: fmt(day90),
    totalWeeks: 13
  }
}];

const browserOutput = $json;
const studentData   = $('2. Code — Prepare Data and Build LinkedIn URL').item.json;

let rawJobData = '';

if (typeof browserOutput.result === 'string')        rawJobData = browserOutput.result;
else if (typeof browserOutput.output === 'string')   rawJobData = browserOutput.output;
else if (typeof browserOutput.content === 'string')  rawJobData = browserOutput.content;
else if (browserOutput.data?.text)                   rawJobData = browserOutput.data.text;
else if (typeof browserOutput.data === 'string')     rawJobData = browserOutput.data;
else                                                 rawJobData = JSON.stringify(browserOutput);

let cleaned = rawJobData
  .replace(/\n{3,}/g, '\n\n')
  .replace(/\t/g, ' ')
  .trim();

if (cleaned.length > 5000) {
  cleaned = cleaned.substring(0, 5000) + '\n[Trimmed to fit processing limit]';
}

if (!cleaned || cleaned.length < 50) {
  throw new Error(
    'BrowserAct returned empty job data. ' +
    'Check that your BrowserAct workflow scrapes LinkedIn job listings correctly. ' +
    'LinkedIn URL used: ' + studentData.linkedinUrl
  );
}

return [{
  json: {
    jobListingsRaw: cleaned,
    jobDataLength: cleaned.length,
    studentName:     studentData.studentName,
    email:           studentData.email,
    targetRole:      studentData.targetRole,
    currentSkills:   studentData.currentSkills,
    skillsArray:     studentData.skillsArray,
    skillsCount:     studentData.skillsCount,
    experienceLevel: studentData.experienceLevel,
    location:        studentData.location,
    weeklyHours:     studentData.weeklyHours,
    linkedinUrl:     studentData.linkedinUrl,
    today:           studentData.today,
    day30:           studentData.day30,
    day60:           studentData.day60,
    day90:           studentData.day90,
    totalWeeks:      studentData.totalWeeks
  }
}];

const output      = $('5. AI Agent — Skill Gap Analysis').item.json.output || '';
const studentData = $('4. Code — Extract Job Data').item.json;

const extract = (label, nextLabel) => {
  const pattern = nextLabel
    ? new RegExp(label + ':\\s*([\\s\\S]*?)(?=\\n' + nextLabel + ':|$)')
    : new RegExp(label + ':\\s*([\\s\\S]*)$');
  const m = output.match(pattern);
  return m ? m[1].trim() : '';
};

const marketSkills      = extract('MARKET_SKILLS_FOUND', 'SKILLS_YOU_HAVE');
const skillsYouHave     = extract('SKILLS_YOU_HAVE', 'SKILLS_MISSING');
const skillsMissing     = extract('SKILLS_MISSING', 'GAP_SCORE');
const gapScore          = extract('GAP_SCORE', 'TOP_3_COURSES');
const top3Courses       = extract('TOP_3_COURSES', 'NINETY_DAY_PLAN');
const ninetyDayPlan     = extract('NINETY_DAY_PLAN', 'MARKET_INSIGHT');
const marketInsight     = extract('MARKET_INSIGHT', 'MOTIVATION_MESSAGE');
const motivationMessage = extract('MOTIVATION_MESSAGE', null);

const missingCount = (skillsMissing.match(/Priority:/g) || []).length;
const haveCount    = (skillsYouHave.match(/\n-/g) || []).length;

if (!skillsMissing || skillsMissing.length < 10) {
  throw new Error(
    'GPT did not return a valid gap analysis. Job data may be insufficient. ' +
    'Preview: ' + output.substring(0, 200)
  );
}

return [{
  json: {
    marketSkills,
    skillsYouHave,
    skillsMissing,
    gapScore,
    top3Courses,
    ninetyDayPlan,
    marketInsight,
    motivationMessage,
    missingCount,
    haveCount,
    studentName:     studentData.studentName,
    email:           studentData.email,
    targetRole:      studentData.targetRole,
    currentSkills:   studentData.currentSkills,
    experienceLevel: studentData.experienceLevel,
    location:        studentData.location,
    weeklyHours:     studentData.weeklyHours,
    linkedinUrl:     studentData.linkedinUrl,
    today:           studentData.today,
    day30:           studentData.day30,
    day60:           studentData.day60,
    day90:           studentData.day90
  }
}];
